+
+    expect(snapshot.config.channels?.slack?.appToken).toEqual({
+      source: "env",
+      provider: "default",
+      id: "MISSING_SLACK_APP_TOKEN",
+    });
+    expect(snapshot.config.channels?.slack?.accounts?.work?.appToken).toEqual({
+      source: "env",
+      provider: "default",
+      id: "MISSING_SLACK_WORK_APP_TOKEN",
